1	import { describe, expect, it } from 'vitest';
2	import { parse } from '../src/parse';
3	import { decorate } from '../src/plugin/decorate';
4	
5	describe('decorate: indentation depth', () => {
6	  it('agrees across heading, list, and paragraph-adjacency encodings', () => {
7	    const md = [
8	      '# Top',
9	      '',
10	      '## Mid',
11	      '',
12	      '### Deep heading',
13	      '',
14	      '- item',
15	      '  - nested item',
16	      '',
17	      'Parent para.',
18	      '- Child para as list item.',
19	      '',
20	    ].join('\n');
21	    const doc = parse(md);
22	    const facts = decorate(doc);
23	
24	    // "# Top" depth 0, "## Mid" depth 1, "### Deep heading" depth 2 (tree
25	    // position, not raw '#' count minus one).
26	    const byLine = new Map(facts.map((f) => [f.lineNumber, f]));
27	    expect(byLine.get(0)?.depth).toBe(0); // # Top
28	    expect(byLine.get(2)?.depth).toBe(1); // ## Mid
29	    expect(byLine.get(4)?.depth).toBe(2); // ### Deep heading
30	
31	    // "- item" is a top-level list under "### Deep heading" -> depth 3;
32	    // "  - nested item" is its child -> depth 4.
33	    expect(byLine.get(6)?.depth).toBe(3); // - item
34	    expect(byLine.get(7)?.depth).toBe(4); // nested item
35	
36	    // Paragraph-adjacency: "Parent para." top-level under the deep heading
37	    // (depth 3, sibling of "- item"); its list-item-encoded paragraph child
38	    // is depth 4 - matching the nested list item's depth exactly.
39	    const parentLine = md.split('\n').indexOf('Parent para.');
40	    const childLine = md.split('\n').indexOf('- Child para as list item.');
41	    expect(byLine.get(parentLine)?.depth).toBe(3);
42	    expect(byLine.get(childLine)?.depth).toBe(4);
43	  });
44	
45	  it('excludes trailing gap (blank separator) lines', () => {
46	    const md = 'First.\n\nSecond.\n';
47	    const doc = parse(md);
48	    const facts = decorate(doc);
49	    const lines = facts.map((f) => f.lineNumber);
50	    expect(lines).toEqual([0, 2]); // line 1 is the blank gap, no fact
51	  });
52	
53	  it('includes multiline node continuation lines at the node’s own depth', () => {
54	    const md = '- item\n  continuation\n';
55	    const doc = parse(md);
56	    const facts = decorate(doc);
57	    expect(facts.map((f) => f.lineNumber)).toEqual([0, 1]);
58	    expect(facts[0]!.depth).toBe(0);
59	    expect(facts[1]!.depth).toBe(0);
60	  });
61	
62	  it('produces no facts for an empty document or preamble-only document', () => {
63	    expect(decorate(parse(''))).toEqual([]);
64	    expect(decorate(parse('---\nt: 1\n---\n'))).toEqual([]);
65	  });
66	
67	  it('decorates every node kind, including atoms', () => {
68	    const md = '# Heading\n\nPara.\n\n- item\n\n```\ncode\n```\n';
69	    const doc = parse(md);
70	    const facts = decorate(doc);
71	    const byLine = new Map(facts.map((f) => [f.lineNumber, f]));
72	
73	    expect(byLine.has(0)).toBe(true); // # Heading
74	    expect(byLine.has(2)).toBe(true); // Para.
75	    expect(byLine.has(4)).toBe(true); // - item
76	    expect(byLine.has(6)).toBe(true); // ```
77	    expect(byLine.has(7)).toBe(true); // code
78	    expect(byLine.has(8)).toBe(true); // ```
79	  });
80	});
81	
82	describe('decorate: first line / native marker flags', () => {
83	  it('marks only the first line of each node as isFirstLine', () => {
84	    const md = 'Para one\nsecond line\n\n- list item\n  continuation\n\n## Heading\n';
85	    const doc = parse(md);
86	    const facts = decorate(doc);
87	    const byLine = new Map(facts.map((f) => [f.lineNumber, f]));
88	
89	    expect(byLine.get(0)?.isFirstLine).toBe(true); // "Para one"
90	    expect(byLine.get(1)?.isFirstLine).toBe(false); // "second line"
91	    expect(byLine.get(3)?.isFirstLine).toBe(true); // "- list item"
92	    expect(byLine.get(4)?.isFirstLine).toBe(false); // list continuation
93	    expect(byLine.get(6)?.isFirstLine).toBe(true); // "## Heading"
94	  });
95	
96	  it('flags hasNativeMarker only for list-item first lines', () => {
97	    const md = 'Para one\n\n- list item\n  continuation\n\n## Heading\n\n```\ncode\n```\n';
98	    const doc = parse(md);
99	    const facts = decorate(doc);
100	    const byLine = new Map(facts.map((f) => [f.lineNumber, f]));
101	
102	    expect(byLine.get(0)?.hasNativeMarker).toBe(false); // "Para one"
103	    expect(byLine.get(2)?.hasNativeMarker).toBe(true); // "- list item"
104	    expect(byLine.get(3)?.hasNativeMarker).toBe(false); // continuation, not first line
105	    expect(byLine.get(5)?.hasNativeMarker).toBe(false); // "## Heading"
106	    expect(byLine.get(7)?.hasNativeMarker).toBe(false); // code fence opener
107	  });
108	
109	  it('flags isAtom only for atom-kind nodes, every one of their lines', () => {
110	    const md = 'Para one\n\n- list item\n\n## Heading\n\n```\ncode line\n```\n';
111	    const doc = parse(md);
112	    const facts = decorate(doc);
113	    const byLine = new Map(facts.map((f) => [f.lineNumber, f]));
114	
115	    expect(byLine.get(0)?.isAtom).toBe(false); // "Para one"
116	    expect(byLine.get(2)?.isAtom).toBe(false); // "- list item"
117	    expect(byLine.get(4)?.isAtom).toBe(false); // "## Heading"
118	    expect(byLine.get(6)?.isAtom).toBe(true); // ``` (opener)
119	    expect(byLine.get(7)?.isAtom).toBe(true); // "code line"
120	    expect(byLine.get(8)?.isAtom).toBe(true); // ``` (closer)
121	  });
122	});
