1	import {
2	  App,
3	  Editor,
4	  MarkdownFileInfo,
5	  MarkdownView,
6	  Notice,
7	  Plugin,
8	  PluginSettingTab,
9	  Setting,
10	  TFile,
11	} from 'obsidian';
12	import type { OutlineDoc, OutlineNode } from '../model';
13	import { parse } from '../parse';
14	import { indent, moveDown, moveUp, outdent } from '../ops';
15	import type { OpOutput } from '../ops';
16	import type { OpResult } from '../result';
17	import { OutlineModeRegistry, DEFAULT_DATA, type PluginData } from './mode-registry';
18	import { nodeAtLine } from './locate';
19	import { editsToChanges } from './dispatch';
20	import { REJECTION_MESSAGES } from './messages';
21	import { compareWithSections, type SectionInfo } from './crosscheck';
22	import { grammarExtension } from './keymap';
23	
24	type StructuralOp = (doc: OutlineDoc, nodeId: number) => OpResult<OpOutput>;
25	
26	const CONFLICTING_PLUGINS = ['obsidian-outliner', 'obsidian-zoom'];
27	
28	export default class TrueOutlinerPlugin extends Plugin {
29	  private data: PluginData = { ...DEFAULT_DATA };
30	  private registry!: OutlineModeRegistry;
31	
32	  override async onload(): Promise<void> {
33	    this.data = { ...DEFAULT_DATA, ...((await this.loadData()) as Partial<PluginData> | null) };
34	    this.registry = new OutlineModeRegistry(async (paths) => {
35	      this.data.outlinePaths = paths;
36	      await this.saveData(this.data);
37	    });
38	    this.registry.hydrate(this.data.outlinePaths);
39	
40	    this.addCommand({
41	      id: 'toggle-outline-mode',
42	      name: 'Toggle outline mode',
43	      editorCheckCallback: (checking, _editor, ctx) => {
44	        const path = ctx.file?.path;
45	        if (!path) return false;
46	        if (!checking) void this.toggleMode(path);
47	        return true;
48	      },
49	    });
50	
51	    this.addStructuralCommand('indent-node', 'Indent node', indent);
52	    this.addStructuralCommand('outdent-node', 'Outdent node', outdent);
53	    this.addStructuralCommand('move-node-up', 'Move node up', moveUp);
54	    this.addStructuralCommand('move-node-down', 'Move node down', moveDown);
55	
56	    this.registerEvent(
57	      this.app.vault.on('rename', (file, oldPath) => {
58	        if (file instanceof TFile) void this.registry.handleRename(oldPath, file.path);
59	      }),
60	    );
61	    this.registerEvent(
62	      this.app.vault.on('delete', (file) => {
63	        if (file instanceof TFile) void this.registry.handleDelete(file.path);
64	      }),
65	    );
66	    this.registerEvent(
67	      this.app.workspace.on('editor-menu', (menu, _editor, info) => {
68	        const path = info.file?.path;
69	        if (!path || !path.endsWith('.md')) return;
70	        const on = this.registry.isOutline(path);
71	        menu.addItem((item) =>
72	          item
73	            .setTitle(on ? 'Disable outline mode' : 'Enable outline mode')
74	            .setIcon('list-tree')
75	            .onClick(() => void this.toggleMode(path)),
76	        );
77	      }),
78	    );
79	
80	    this.registerEditorExtension(grammarExtension(this));
81	
82	    this.addSettingTab(new TrueOutlinerSettingTab(this.app, this));
83	
84	    this.app.workspace.onLayoutReady(() => void this.warnAboutConflicts());
85	  }
86	
87	  isOutline(path: string): boolean {
88	    return this.registry.isOutline(path);
89	  }
90	
91	  get debugCrossCheck(): boolean {
92	    return this.data.debugCrossCheck;
93	  }
94	
95	  async setDebugCrossCheck(value: boolean): Promise<void> {
96	    this.data.debugCrossCheck = value;
97	    await this.saveData(this.data);
98	  }
99	
100	  private async toggleMode(path: string): Promise<void> {
101	    const on = await this.registry.toggle(path);
102	    new Notice(on ? 'Outline mode on' : 'Outline mode off', 1500);
103	  }
104	
105	  private addStructuralCommand(id: string, name: string, op: StructuralOp): void {
106	    this.addCommand({
107	      id,
108	      name,
109	      editorCheckCallback: (checking, editor, ctx) => {
110	        const path = ctx.file?.path;
111	        if (!path || !this.registry.isOutline(path)) return false;
112	        if (!checking) this.runOp(editor, ctx, op);
113	        return true;
114	      },
115	    });
116	  }
117	
118	  private runOp(editor: Editor, ctx: MarkdownView | MarkdownFileInfo, op: StructuralOp): void {
119	    // Fresh-tree guarantee: always parse the current buffer at invocation.
120	    const text = editor.getValue();
121	    const doc = parse(text);
122	    if (this.data.debugCrossCheck && ctx.file) this.crossCheck(doc, ctx.file);
123	
124	    const node: OutlineNode | undefined = nodeAtLine(doc, editor.getCursor().line);
125	    if (!node) {
126	      new Notice(REJECTION_MESSAGES['node-not-found'], 1500);
127	      return;
128	    }
129	    const result = op(doc, node.id);
130	    if (!result.ok) {
131	      new Notice(REJECTION_MESSAGES[result.rejection.reason], 1500);
132	      return;
133	    }
134	    const lines = text === '' ? [] : text.split('\n');
135	    const changes = editsToChanges(lines, result.value.edits);
136	    if (changes.length > 0) editor.transaction({ changes });
137	    editor.setCursor(result.value.cursor);
138	  }
139	
140	  private crossCheck(doc: OutlineDoc, file: TFile): void {
141	    const sections = this.app.metadataCache.getFileCache(file)?.sections;
142	    if (!sections) return;
143	    const mapped: SectionInfo[] = sections.map((section) => ({
144	      type: section.type,
145	      startLine: section.position.start.line,
146	      endLine: section.position.end.line,
147	    }));
148	    const issues = compareWithSections(doc, mapped);
149	    if (issues.length > 0) {
150	      console.warn(
151	        `[true-outliner] parse disagreement in ${file.path} — candidate corpus fixture:`,
152	        issues,
153	      );
154	    }
155	  }
156	
157	  private async warnAboutConflicts(): Promise<void> {
158	    if (this.data.coexistenceWarned) return;
159	    const configPath = `${this.app.vault.configDir}/community-plugins.json`;
160	    let enabled: string[] = [];
161	    try {
162	      enabled = JSON.parse(await this.app.vault.adapter.read(configPath)) as string[];
163	    } catch {
164	      return; // no community plugins file — nothing to warn about
165	    }
166	    const conflicts = CONFLICTING_PLUGINS.filter((id) => enabled.includes(id));
167	    if (conflicts.length === 0) return;
168	    new Notice(
169	      `True Outliner: ${conflicts.join(' and ')} ${conflicts.length > 1 ? 'are' : 'is'} enabled — ` +
170	        'overlapping outliner behavior and keybindings may conflict.',
171	      8000,
172	    );
173	    this.data.coexistenceWarned = true;
174	    await this.saveData(this.data);
175	  }
176	}
177	
178	class TrueOutlinerSettingTab extends PluginSettingTab {
179	  constructor(
180	    app: App,
181	    private readonly plugin: TrueOutlinerPlugin,
182	  ) {
183	    super(app, plugin);
184	  }
185	
186	  override display(): void {
187	    this.containerEl.empty();
188	    new Setting(this.containerEl)
189	      .setName('Debug: cross-check parser against metadata cache')
190	      .setDesc(
191	        'Logs disagreements between the plugin parser and Obsidian metadata to the developer console when a structural command runs.',
192	      )
193	      .addToggle((toggle) =>
194	        toggle
195	          .setValue(this.plugin.debugCrossCheck)
196	          .onChange((value) => void this.plugin.setDebugCrossCheck(value)),
197	      );
198	  }
199	}
