/** Dump outerHTML of the Nth `.cm-line` — for one-off DOM discovery, not assertions. */
export function dumpLineHtml(lineIndex: number): Promise<string> {
  return browser.executeObsidian(
    ({ app, obsidian }, lineIndex) => {
      const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
      if (!view) throw new Error('no active markdown view');
      const cm = (view.editor as any).cm;
      const lines = cm.contentDOM.querySelectorAll(':scope > .cm-line');
      const el = lines[lineIndex] as HTMLElement | undefined;
      return el?.outerHTML ?? '(missing)';
    },
    lineIndex,
  );
}

